const results = [];
for (const item of items) {
  const now = new Date();
  const todayDateIST = now.toLocaleDateString('en-GB', { timeZone: 'Asia/Kolkata', day: '2-digit', month: '2-digit', year: 'numeric' });
  const todayWeekdayIST = now.toLocaleDateString('en-GB', { timeZone: 'Asia/Kolkata', weekday: 'long' });
  const fullDateTimeIST = now.toLocaleString('en-GB', { timeZone: 'Asia/Kolkata', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit' });
  item.json.system_today = todayDateIST;
  item.json.system_weekday = todayWeekdayIST;
  item.json.system_datetime = fullDateTimeIST;
  results.push(item);
}
return results;

const aiResponse = $('AI Agent').first().json.output;
if (aiResponse.includes('[SEND]')) {
  const messages = aiResponse.split('[SEND]').map(msg => msg.trim()).filter(msg => msg.length > 0);
  return messages.map((message, index) => ({ json: { message, messageIndex: index + 1, totalMessages: messages.length, originalResponse: aiResponse, timestamp: new Date().toISOString() } }));
} else {
  return [{ json: { message: aiResponse, messageIndex: 1, totalMessages: 1, originalResponse: aiResponse, timestamp: new Date().toISOString() } }];
}

const trig = $('WhatsApp Trigger').item.json || {};
const split0 = $('Split Messages').first().json || {};
const phoneNumber = trig.contacts?.[0]?.wa_id || trig.messages?.[0]?.from || 'unknown';
const userName = $('WhatsApp Trigger').first().json.contacts[0].profile.name || 'Unknown';
const userMessage = trig.messages?.[0]?.text?.body || '';
const botResponse = split0.originalResponse || split0.message || '';
const now = new Date();
const formattedDate = now.toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', year: 'numeric', month: '2-digit', day: '2-digit' });
const formattedTime = now.toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
const timestamp = now.toISOString();
const sessionId = `${phoneNumber}_${now.toISOString().slice(0,10)}`;
const um = (userMessage || '').toLowerCase();
const br = (botResponse || '').toLowerCase();
let conversationStage = 'Inquiry';
if (um.includes('hi') || um.includes('hello')) conversationStage = 'Initial Contact';
else if (br.includes('consultation') || br.includes('expert')) conversationStage = 'Conversion Attempt';
else if (br.includes('routine') || br.includes('plan')) conversationStage = 'Solution Provided';
return [{ json: { timestamp, date: formattedDate, time: formattedTime, phoneNumber, userName, userMessage, botResponse, conversationStage, sessionId, messageLength: botResponse.length || 0, splitMessages: split0.totalMessages || 1 } }];

const split0 = $('Split Messages').first().json || {};
const originalResponse = split0.originalResponse || split0.message || '';
return [{ json: { message: originalResponse, timestamp: new Date().toISOString() } }];

const response = $('AI Agent').first().json.output || '';
const phoneNumber = $('WhatsApp Trigger').first().json.contacts[0].wa_id || '';

// Extract Name
const nameMatch = response.match(/Name:\s*([^,\n]+)/i);
const patientName = nameMatch ? nameMatch[1].trim() : 'Patient';

// Extract Mobile
const mobileMatch = response.match(/Mobile:\s*(\d+)/i);
const mobile = mobileMatch ? mobileMatch[1].trim() : phoneNumber;

// Extract Email
const emailMatch = response.match(/Email:\s*([^\s,\n]+@[^\s,\n]+)/i);
const email = emailMatch ? emailMatch[1].trim() : '';

// Extract Department — handle all AI phrasings
const deptMatch = response.match(
  /(?:Confirmed for|Teleconsultation arranged for|Specialist appointment for|appointment for|Confirmed in-person)\s+([\w\s,()-]+?)\s+on\s/i
);
const department = deptMatch ? deptMatch[1].trim() : 'OPD';

// Handle both 'on Friday, 24 Apr 2026' and 'on 24 Apr 2026' with short/long month names
const dateTimeMatch = response.match(
  /on\s+(?:\w+,\s+)?(\d{1,2}\s+\w+\s+\d{4})\s+at\s+(\d{1,2}:\d{2}\s*(?:AM|PM))/i
);

let startISO = '';
let endISO = '';

if (dateTimeMatch) {
  const combined = dateTimeMatch[1] + ' ' + dateTimeMatch[2];
  const parsed = new Date(combined + ' +0530');
  if (!isNaN(parsed.getTime())) {
    startISO = parsed.toISOString();
    endISO = new Date(parsed.getTime() + 30 * 60 * 1000).toISOString();
  }
}

if (!startISO) {
  throw new Error('Could not parse booking date/time from AI response. Response: ' + response);
}

return [{
  json: { patientName, mobile, email, department, startISO, endISO, phoneNumber, originalResponse: response }
}];

